import{_ as t,o,c as n,a3 as i}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"62. Union Matters","description":"","frontmatter":{"title":"62. Union Matters","eba":"Medical Specialists 2022-2026","topics":["union-matters"]},"headers":[],"relativePath":"ebas/medical-specialists/union-matters/62-union-matters.md","filePath":"ebas/medical-specialists/union-matters/62-union-matters.md"}'),a={name:"ebas/medical-specialists/union-matters/62-union-matters.md"};function s(r,e,c,l,p,h){return o(),n("div",null,[...e[0]||(e[0]=[i('<h1 id="_62-union-matters" tabindex="-1">62. Union Matters <a class="header-anchor" href="#_62-union-matters" aria-label="Permalink to &quot;62. Union Matters&quot;">​</a></h1><p><strong>62.1</strong> Access to Doctors – General</p><p>The Association will have access to Doctors for any process arising under this Agreement.</p><p><strong>62.2</strong> Access to Doctors – Electronic communication</p><p>A Health Service will ensure that:</p><p><strong>(a)</strong> emails from the Association domain name are not blocked or restricted by or on behalf of the Health Service, except in respect of any individual Doctor who has made a written request to the Health Service to block such emails;</p><p><strong>(b)</strong> emails from Doctors to the Association are not blocked or restricted by or on behalf of the Health Service;</p><p><strong>(c)</strong> access from Health Service computers and like devices to Association websites and online information is not blocked, or limited; and</p><p><strong>(d)</strong> where a genuine security concern arises regarding the above, the Health Service will immediately notify the Association to enable the security concern to be addressed.</p><p><strong>62.3</strong> Access to Doctors – Orientation</p><p><strong>(a)</strong> The Association may attend and address new Doctors as part of orientation / induction programs for new Doctors, provided that any attendance for the purposes of discussions with the Doctors meets the right of entry requirements under Part 3-4 of the Act (Entry Requirements). The details of such attendance will be arranged by the Health Service in consultation with the Association.</p><p><strong>(b)</strong> A Health Service will advise the Association of the date, time and location of orientation / induction programs not less than 14 days prior to the orientation / induction program.</p><p><strong>(c)</strong> Those covered by this Agreement acknowledge the increasing role that technology plays in orientation / induction. A Health Service and Association may agree to an alternative means by which the Association can access new Doctors including where orientation / induction programs are conducted on- line or the Association cannot reasonably attend, provided that such access is consistent with the Entry Requirements.</p><p><strong>62.4</strong> AMA / ASMOF Ambassador (Ambassador) and Health &amp; Safety Representatives</p><p>NOTE: Additional rights of HSRs are contained in the OHS Act.</p><p><strong>(a)</strong> In this subclause 62.4, Representative means an Ambassador or HSR.</p><p><strong>(b)</strong> A Representative is entitled to reasonable time release from duty to:</p><p><strong>(i)</strong> attend to matters relating to industrial, occupational health and safety or other relevant matters such as assisting with grievance procedures and attending committee meetings;</p><p><strong>(ii)</strong> access reasonable preparation time before meetings with management or disciplinary or grievance meetings with a member of the Association;</p><p><strong>(iii)</strong> appear as a witness or participate in conciliation or arbitration, before the FWC;</p><p><strong>(iv)</strong> present information on the Association at orientation sessions for new Doctors.</p><p><strong>(c)</strong> A Representative required to attend management or consultative meetings outside of paid time will be paid to attend.</p><p><strong>(d)</strong> A Representative will be provided with access to facilities such as telephones, computers, email, noticeboards and meeting rooms in a manner that does not adversely affect service delivery and work requirements of the Health Service. In the case of an HSR, facilities will include other facilities as necessary to enable them to perform their functions as prescribed under the OHS Act.</p><p><strong>62.5</strong> Noticeboard</p><p><strong>(a)</strong> A noticeboard for the Association’s use will be readily accessible in each ward/unit/work area or nearest staff room where persons eligible to be members of the Association are employed.</p><p><strong>(b)</strong> The Association and members covered by this Agreement will, during the life of this Agreement, consult over the development of an electronic noticeboard managed by the Association.</p><p><strong>62.6</strong> Meeting Space</p><p>In the absence of agreement on a location for the holding of Association meetings, the room where one or more of the Doctors who may participate in the meeting ordinarily take meal or other breaks will be the meeting room for the purpose of Association meetings. Nothing in this clause is intended to override the operation of the Act.</p><p><strong>62.7</strong> Secondment to the Association</p><p>A Health Service will, on application, grant leave without pay to a Doctor for the purpose of secondment or other arrangement to work for the Association subject to the Health Service’s reasonable operational requirements.</p><p><strong>62.8</strong> Doctors holding official positions with the Association</p><p>A Health Service will, on application by the Association, grant leave without loss of pay to a Doctor for the purpose of fulfilling their duties as an official of the Council or Executive body of the Association. For a member of the AMA/ASMOF Council, this currently involves 4 meetings per year (plus travel time). For AMA/ASMOF Executive Council members this involves an additional 12 meetings (plus travel time).</p><p><strong>62.9</strong> Association Training</p><p>NOTE: A HSR may be entitled to any training in accordance with the OHS Act rather than, or in addition to, this clause.</p><p><strong>(a)</strong> Subject to the conditions in this subclause 62.9, Doctors selected by the Association to attend training courses on industrial relations and/or health and safety will be entitled to a maximum of five days’ paid leave per calendar year per Doctor.</p><p><strong>(b)</strong> Leave in excess of five days and up to ten days may be granted in a calendar year subject to the total leave being granted in that year and in the subsequent year not exceeding ten days.</p><p><strong>(c)</strong> The granting of leave will be subject to the Health Service’s operational requirements. The granting of leave will not be unreasonably withheld.</p><p><strong>(d)</strong> Leave under this subclause is granted on the following conditions:</p><p><strong>(i)</strong> applications are accompanied by a statement from the Association advising that it has nominated the Doctor or supports the application:</p><p><strong>(ii)</strong> the training is conducted by the Association, an association of unions or accredited training provider; and</p><p><strong>(iii)</strong> the application is made as early as practicable and not less than two (2) weeks before the training.</p><p><strong>(e)</strong> The Doctor will be paid the Doctor’s ordinary pay for normal rostered hours but excluding shift work, overtime and other allowances.</p><p><strong>(f)</strong> Leave in accordance with this clause may include necessary travelling time in normal hours immediately before or after the course.</p><p><strong>(g)</strong> Leave granted under this clause will count as service for all purposes of this Agreement.</p><p><strong>(h)</strong> Expenses associated with attendance at training courses, including fares, accommodation and meal costs are not the responsibility of the Health Service.</p><p><strong>62.10</strong> Agreement Implementation Committees</p><p><strong>(a)</strong> A local agreement implementation committee (AIC) will continue or, if there is not currently an AIC in operation, be established at each Health Service. Having regard for the size and location, an AIC may be appropriate at each facility/campus. The AIC will, where practicable, comprise equal numbers of representatives of the Health Service and the AMA/ASMOF for the purposes of:</p><p><strong>(i)</strong> agreement implementation;</p><p><strong>(ii)</strong> on-going monitoring and assessment of the implementation of this Agreement; and</p><p><strong>(iii)</strong> dealing with any local disputes that may arise, without limiting the Dispute Resolution Procedure in this Agreement.</p><p><strong>(b)</strong> Priority items for consideration by the AIC will be developed by the parties.</p><p>Plain language terms: union rep, delegate.</p>',52)])])}const m=t(a,[["render",s]]);export{g as __pageData,m as default};
